initScript:
await ManagerApi.ready();
const fileApiBase = ManagerApi.getBase() + '/file';
const dirApiBase = ManagerApi.getBase() + '/dir';
const siteApiBase = ManagerApi.getBase() + '/site';
const workspaceRoot = (await utils.postForm(siteApiBase + '/get_root.php', {})).trim().replace(/\/$/, '');
const m = workspaceRoot.match(/^([A-Za-z]:)\//);
assert(m && m[1], 'disk init: cannot resolve drive root');
const driveRoot = m[1] + '/';
const diskPost = (url, data) => utils.postForm(url, Object.assign({ disk: 1 }, data || {}));
return {
  workspaceRoot,
  driveRoot,
  diskPost,
  diskDirName: 'shv-disk-dir',
  diskDirRenamed: 'shv-disk-dir-renamed',
  diskFileName: 'shv-disk-file.txt',
  diskFileRenamed: 'shv-disk-file-renamed.txt',
  createDirUrl: dirApiBase + '/create_dir.php',
  scanDirUrl: dirApiBase + '/scan_dir.php',
  renameDirUrl: dirApiBase + '/rename_dir.php',
  deleteDirUrl: dirApiBase + '/delete_dir.php',
  createFileUrl: fileApiBase + '/create_file.php',
  scanFileUrl: fileApiBase + '/scan_file.php',
  writeFileUrl: fileApiBase + '/write_file.php',
  readFileUrl: fileApiBase + '/read_file.php',
  renameFileUrl: fileApiBase + '/rename_file.php',
  deleteFileUrl: fileApiBase + '/delete_file.php',
  message: 'init done: ' + driveRoot
};

finallyScript:
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirName + '/' + diskFileName }); } catch (_) {}
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirName + '/' + diskFileRenamed }); } catch (_) {}
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirRenamed + '/' + diskFileName }); } catch (_) {}
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirRenamed + '/' + diskFileRenamed }); } catch (_) {}
for (const d of [diskDirName, diskDirRenamed]) {
  try { await diskPost(deleteDirUrl, { path: driveRoot + d + '/' }); } catch (_) {}
}
return { message: 'cleanup done' };

tests.scriptText:
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirName + '/' + diskFileName }); } catch (_) {}
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirName + '/' + diskFileRenamed }); } catch (_) {}
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirRenamed + '/' + diskFileName }); } catch (_) {}
try { await diskPost(deleteFileUrl, { path: driveRoot + diskDirRenamed + '/' + diskFileRenamed }); } catch (_) {}
try { await diskPost(deleteDirUrl, { path: driveRoot + diskDirName + '/' }); } catch (_) {}
try { await diskPost(deleteDirUrl, { path: driveRoot + diskDirRenamed + '/' }); } catch (_) {}
const dt = await diskPost(createDirUrl, { dir: driveRoot, name: diskDirName });
const dm = dt.match(/\[(.+?)\/\]/);
assert(dm && dm[1], 'create_dir: parse fail');
const dirPath = dm[1];
const ft = await diskPost(createFileUrl, { dir: dirPath + '/', name: diskFileName });
const fm = ft.match(/\[(.+?)\]/);
assert(fm && fm[1], 'create_file: parse fail');
return { dirPath, filePath: fm[1], message: 'created dir + file' };

await diskPost(writeFileUrl, { path: filePath, content: 'disk path test content' });
const text = await diskPost(readFileUrl, { path: filePath });
assert(text.includes('disk path test content'), 'write_read: content mismatch');
return { message: 'write/read ok' };

const dirs = JSON.parse((await diskPost(scanDirUrl, { path: driveRoot })) || '[]');
const files = JSON.parse((await diskPost(scanFileUrl, { path: dirPath + '/' })) || '[]');
assert(Array.isArray(dirs), 'scan: dirs not array');
assert(Array.isArray(files), 'scan: files not array');
assert(dirs.includes(utils.basename(dirPath)), 'scan: dir missing');
assert(files.includes(utils.basename(filePath)), 'scan: file missing');
return { message: 'scan ok' };

const dt = await diskPost(renameDirUrl, { path: dirPath + '/', name: diskDirRenamed });
const dm = dt.match(/to \[(.+?)\/\]/);
assert(dm && dm[1], 'rename dir: parse fail');
dirPath = dm[1];
const ft = await diskPost(renameFileUrl, { path: dirPath + '/' + utils.basename(filePath), name: diskFileRenamed });
const fm = ft.match(/to \[(.+?)\]/);
assert(fm && fm[1], 'rename file: parse fail');
filePath = fm[1];
return { dirPath, filePath, message: 'renamed both' };

await diskPost(deleteFileUrl, { path: filePath });
await diskPost(deleteDirUrl, { path: dirPath + '/' });
const dirs = JSON.parse((await diskPost(scanDirUrl, { path: driveRoot })) || '[]');
assert(Array.isArray(dirs), 'delete verify: dirs not array');
assert(!dirs.includes(utils.basename(dirPath)), 'delete verify: dir still exists');
return { message: 'deleted + verified' };
